import React from 'react';
import { motion } from 'framer-motion';
import { FaCalendar, FaClock, FaUser } from 'react-icons/fa';

const Blog = () => {
  const blogPosts = [
    {
      title: "Getting Started with React Hooks",
      excerpt: "Learn how to use React Hooks to manage state and side effects in your functional components.",
      date: "March 15, 2024",
      readTime: "5 min read",
      author: "Your Name",
      image: "/blog1.jpg",
      category: "React",
      link: "https://yourblog.com/react-hooks"
    },
    {
      title: "The Future of Web Development",
      excerpt: "Explore the latest trends and technologies shaping the future of web development.",
      date: "March 10, 2024",
      readTime: "8 min read",
      author: "Your Name",
      image: "/blog2.jpg",
      category: "Web Development",
      link: "https://yourblog.com/future-web"
    },
    {
      title: "Optimizing React Performance",
      excerpt: "Discover techniques and best practices for improving the performance of your React applications.",
      date: "March 5, 2024",
      readTime: "6 min read",
      author: "Your Name",
      image: "/blog3.jpg",
      category: "Performance",
      link: "https://yourblog.com/react-performance"
    }
  ];

  return (
    <section id="blog" className="section">
      <div className="container">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
          viewport={{ once: true }}
          className="text-center mb-16"
        >
          <h2 className="heading">Blog</h2>
          <p className="subheading">Latest articles and tutorials</p>
        </motion.div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {blogPosts.map((post, index) => (
            <motion.article
              key={index}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
              viewport={{ once: true }}
              className="bg-tertiary rounded-lg overflow-hidden group"
            >
              {/* Blog Image */}
              <div className="relative h-48 overflow-hidden">
                <div className="absolute inset-0 bg-secondary opacity-20 group-hover:opacity-30 transition-opacity"></div>
                <div className="w-full h-full bg-primary flex items-center justify-center">
                  <span className="text-2xl text-secondary">{post.title}</span>
                </div>
              </div>

              {/* Blog Content */}
              <div className="p-6">
                <div className="flex items-center gap-4 text-sm text-textSecondary mb-4">
                  <span className="flex items-center gap-1">
                    <FaCalendar />
                    {post.date}
                  </span>
                  <span className="flex items-center gap-1">
                    <FaClock />
                    {post.readTime}
                  </span>
                  <span className="flex items-center gap-1">
                    <FaUser />
                    {post.author}
                  </span>
                </div>

                <h3 className="text-xl font-semibold mb-2 group-hover:text-secondary transition-colors">
                  {post.title}
                </h3>
                <p className="text-textSecondary mb-4">
                  {post.excerpt}
                </p>

                <div className="flex items-center justify-between">
                  <span className="px-3 py-1 bg-primary text-secondary rounded-full text-sm">
                    {post.category}
                  </span>
                  <a
                    href={post.link}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="text-secondary hover:text-opacity-80 transition-colors"
                  >
                    Read More →
                  </a>
                </div>
              </div>
            </motion.article>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Blog;
